mapper.select:
select
from appointment a left join customer c on a.customer_id = c.id left join employee e on a.employee_id = e.id left join service_item si on a.service_item_id = si.id
a.deleted = 0
and c.name like concat('%', #{query.customerName}, '%')
and e.name like concat('%', #{query.employeeName}, '%')
and a.status = #{query.status}
and a.appointment_time >= #{query.beginTime}
and a.appointment_time <= #{query.endTime}
order by a.create_time desc
